export const DeleteordersclientorderidHeader = zod.object({
  "timestamp": zod.string().optional().describe('밀리세컨드 단위 타임스탬프. nonce 대신 사용할 수 있습니다.'),
  "nonce": zod.string().optional().describe('timestamp 대신 사용할 수 있는 증가하는 난스 값.'),
  "signature": zod.string().describe('HMAC-SHA512 서명값(base64 인코딩).'),
  "receive-window": zod.number().min(deleteordersclientorderidHeaderReceiveWindowMin).max(deleteordersclientorderidHeaderReceiveWindowMax).optional().describe('리시브 윈도 (200~60000 밀리세컨드).')
})
